operations.schema:
input AssignInvestigatorInput {
    id: OID!
    assignedTo: String!
}

operations.reducer:
const d = state.disputes.find((x) => x.id === action.input.id);
if (!d) throw new Error(`Dispute ${action.input.id} not found`);
d.assignedTo = action.input.assignedTo;
d.status = "INVESTIGATING";

operations.schema:
input ResolveDisputeInput {
    id: OID!
    resolvedAt: DateTime!
    resolution: String!
}

operations.reducer:
const d = state.disputes.find((x) => x.id === action.input.id);
if (!d) throw new Error(`Dispute ${action.input.id} not found`);
d.resolvedAt = action.input.resolvedAt;
d.resolution = action.input.resolution;
d.status = "RESOLVED";

operations.schema:
input DismissDisputeInput {
    id: OID!
    dismissedAt: DateTime!
    reason: String!
}

operations.reducer:
const d = state.disputes.find((x) => x.id === action.input.id);
if (!d) throw new Error(`Dispute ${action.input.id} not found`);
d.resolvedAt = action.input.dismissedAt;
d.resolution = action.input.reason;
d.status = "DISMISSED";

operations.schema:
input AppealDisputeInput {
    id: OID!
    appealAt: DateTime!
    appealReason: String!
}

operations.reducer:
const d = state.disputes.find((x) => x.id === action.input.id);
if (!d) throw new Error(`Dispute ${action.input.id} not found`);
d.appealAt = action.input.appealAt;
d.appealReason = action.input.appealReason;
d.status = "APPEALED";

state.publisherDecisions.push({
  id: action.input.id,
  grantSystemRef: action.input.grantSystemRef,
  decision: action.input.decision,
  decidedBy: action.input.decidedBy,
  decidedAt: action.input.decidedAt,
  reason: action.input.reason || null,
});

state.rfcs.push({
  id: action.input.id,
  title: action.input.title,
  summary: action.input.summary,
  author: action.input.author,
  proposedAt: action.input.proposedAt,
  status: "PROPOSED",
  ratifiedAt: null,
  implementedAt: null,
});

const r = state.rfcs.find((x) => x.id === action.input.id);
if (!r) throw new Error(`RFC ${action.input.id} not found`);
r.status = "UNDER_REVIEW";

operations.schema:
input RatifyRfcInput {
    id: OID!
    ratifiedAt: DateTime!
}

operations.reducer:
const r = state.rfcs.find((x) => x.id === action.input.id);
if (!r) throw new Error(`RFC ${action.input.id} not found`);
r.status = "RATIFIED";
r.ratifiedAt = action.input.ratifiedAt;

operations.schema:
input ImplementRfcInput {
    id: OID!
    implementedAt: DateTime!
}

operations.reducer:
const r = state.rfcs.find((x) => x.id === action.input.id);
if (!r) throw new Error(`RFC ${action.input.id} not found`);
r.status = "IMPLEMENTED";
r.implementedAt = action.input.implementedAt;

const r = state.rfcs.find((x) => x.id === action.input.id);
if (!r) throw new Error(`RFC ${action.input.id} not found`);
r.status = "REJECTED";

const r = state.rfcs.find((x) => x.id === action.input.id);
if (!r) throw new Error(`RFC ${action.input.id} not found`);
r.status = "WITHDRAWN";

state.policies.push({
  id: action.input.id,
  name: action.input.name,
  summary: action.input.summary,
  content: action.input.content,
  effectiveFrom: action.input.effectiveFrom,
  supersededAt: null,
  supersededBy: null,
});

operations.schema:
input SupersedePolicyInput {
    id: OID!
    supersededAt: DateTime!
    supersededBy: OID!
}

operations.reducer:
const p = state.policies.find((x) => x.id === action.input.id);
if (!p) throw new Error(`Policy ${action.input.id} not found`);
p.supersededAt = action.input.supersededAt;
p.supersededBy = action.input.supersededBy;
